<div class="blog-post">
  <h2><%= post.title %></h2>
  <p class="author">By <%= post.user.name %> on <%= post.created_at.strftime("%B %d, %Y") %></p>
  <div class="content">
    <%= raw post.content %>
  </div>
</div>